import json
from web3 import Web3
import sys

def deploy_protocol():
    print("🏛️  [STG-WEB5] INJEKSI BINER PROTOKOL METAPORTASI...")
    w3 = Web3(Web3.HTTPProvider('http://127.0.0.1:8545'))
    
    if not w3.is_connected():
        print("❌ Sinyal Ganache Putus!")
        return

    # Bytecode Lengkap dari Intelijen Quorom-State Anda
    bytecode = ""

    admin = w3.eth.accounts[0]
    
    print("🚀 Meluncurkan Protokol Metaportasi...")
    try:
        tx_hash = w3.eth.send_transaction({
            'from': admin,
            'data': bytecode,
            'gas': 4000000
        })
        
        tx_receipt = w3.eth.wait_for_transaction_receipt(tx_hash)
        print("==================================================")
        print(f"✅ METAPORTATION PROTOCOL LIVE!")
        print(f"Alamat: {tx_receipt.contractAddress}")
        print("==================================================")
        
        # Simpan status untuk sinkronisasi 114 BT
        with open("metaport_status.json", "w") as f:
            json.dump({"address": tx_receipt.contractAddress, "status": "ACTIVE"}, f)
            
    except Exception as e:
        print(f"❌ Kegagalan Injeksi: {e}")

if __name__ == "__main__":
    deploy_protocol()
